import { useState } from "react";
import "./App.css";

const FRAMEWORKS = ["NIST SP 800-53", "NIST CSF 2.0", "FedRAMP", "CIS Controls v8"];
const ENVS = ["AWS", "Azure", "GCP", "Multi-cloud"];

export default function App() {
  const [input, setInput] = useState("");
  const [env, setEnv] = useState("AWS");
  const [framework, setFramework] = useState("NIST SP 800-53");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  async function assess() {
    setError(""); setResult(null); setLoading(true);
    try {
      const res = await fetch("/api/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 1000,
          system: `You are a senior GRC analyst for ${env} environments using ${framework}. Return ONLY valid JSON (no markdown) with keys: assessmentQuestions (array), evidenceToCollect (array), potentialWeaknesses (array of {name, description, severity}), nistControls (array of {id, name, rationale}). Be specific to ${env}.`,
          messages: [{ role: "user", content: `Assess this security control:\n\n${input}` }]
        })
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error.message);
      const text = data.content.find(b => b.type === "text")?.text || "";
      setResult(JSON.parse(text.replace(/```json|```/g, "").trim()));
    } catch (e) {
      setError(e.message);
    }
    setLoading(false);
  }

  return (
    <div style={{ maxWidth: 720, margin: "0 auto", padding: "2rem 1rem", fontFamily: "system-ui, sans-serif" }}>
      <span style={{ fontSize: 11, background: "#dbeafe", color: "#1e40af", padding: "3px 10px", borderRadius: 99, fontWeight: 600 }}>
        GRC Portfolio Tool
      </span>
      <h1 style={{ fontSize: 26, fontWeight: 600, margin: "0.75rem 0 0.25rem" }}>Security Control Assessor</h1>
      <p style={{ color: "#6b7280", marginBottom: "1.5rem" }}>
        Powered by Claude AI · Generates assessment questions, evidence checklists, weaknesses & {framework} mappings
      </p>

      <div style={{ background: "#fff", border: "1px solid #e5e7eb", borderRadius: 12, padding: "1.25rem", marginBottom: "1rem" }}>
        <label style={{ fontSize: 13, fontWeight: 500, color: "#374151", display: "block", marginBottom: 6 }}>
          Control description or system detail
        </label>
        <textarea
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="Example: Our AWS environment uses IAM roles with least-privilege for EC2. MFA is enforced on root and all IAM users. Access keys rotate every 90 days via Lambda..."
          style={{ width: "100%", minHeight: 120, padding: "0.75rem", borderRadius: 8, border: "1px solid #d1d5db", fontSize: 14, resize: "vertical", fontFamily: "inherit", boxSizing: "border-box" }}
        />
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginTop: 10 }}>
          <div>
            <label style={{ fontSize: 12, color: "#6b7280", display: "block", marginBottom: 4 }}>Cloud environment</label>
            <select value={env} onChange={e => setEnv(e.target.value)}
              style={{ width: "100%", padding: "0.45rem 0.75rem", borderRadius: 8, border: "1px solid #d1d5db", fontSize: 13 }}>
              {ENVS.map(e => <option key={e}>{e}</option>)}
            </select>
          </div>
          <div>
            <label style={{ fontSize: 12, color: "#6b7280", display: "block", marginBottom: 4 }}>Compliance framework</label>
            <select value={framework} onChange={e => setFramework(e.target.value)}
              style={{ width: "100%", padding: "0.45rem 0.75rem", borderRadius: 8, border: "1px solid #d1d5db", fontSize: 13 }}>
              {FRAMEWORKS.map(f => <option key={f}>{f}</option>)}
            </select>
          </div>
        </div>
        <button onClick={assess} disabled={loading || !input.trim()}
          style={{ width: "100%", marginTop: 12, padding: "0.65rem", borderRadius: 8, border: "1px solid #d1d5db", background: loading ? "#f3f4f6" : "#1e293b", color: loading ? "#9ca3af" : "#fff", fontSize: 14, fontWeight: 500, cursor: loading ? "not-allowed" : "pointer" }}>
          {loading ? "Analyzing…" : "⚡ Assess control"}
        </button>
      </div>

      {error && <div style={{ background: "#fef2f2", border: "1px solid #fecaca", borderRadius: 8, padding: "0.75rem 1rem", color: "#b91c1c", fontSize: 13, marginBottom: "1rem" }}>{error}</div>}

      {result && <Results result={result} framework={framework} />}
    </div>
  );
}

function Results({ result, framework }) {
  const sevColor = s => s === "High" ? ["#fef2f2","#b91c1c"] : s === "Medium" ? ["#fffbeb","#92400e"] : ["#f0fdf4","#166534"];
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "0.75rem" }}>
      <Card icon="❓" title="Assessment questions">
        <ul style={{ paddingLeft: "1.25rem", display: "flex", flexDirection: "column", gap: 6 }}>
          {result.assessmentQuestions.map((q, i) => <li key={i} style={{ fontSize: 13, lineHeight: 1.6 }}>{q}</li>)}
        </ul>
      </Card>
      <Card icon="📋" title="Evidence to collect">
        <ul style={{ paddingLeft: "1.25rem", display: "flex", flexDirection: "column", gap: 6 }}>
          {result.evidenceToCollect.map((e, i) => <li key={i} style={{ fontSize: 13, lineHeight: 1.6 }}>{e}</li>)}
        </ul>
      </Card>
      <Card icon="⚠️" title="Potential weaknesses">
        {result.potentialWeaknesses.map((w, i) => {
          const [bg, tc] = sevColor(w.severity);
          return <div key={i} style={{ padding: "0.6rem 0", borderBottom: i < result.potentialWeaknesses.length - 1 ? "1px solid #f3f4f6" : "none" }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 3 }}>
              <span style={{ fontSize: 13, fontWeight: 500 }}>{w.name}</span>
              <span style={{ fontSize: 11, fontWeight: 600, padding: "2px 8px", borderRadius: 99, background: bg, color: tc, marginLeft: "auto" }}>{w.severity}</span>
            </div>
            <p style={{ fontSize: 12, color: "#6b7280", lineHeight: 1.55, margin: 0 }}>{w.description}</p>
          </div>;
        })}
      </Card>
      <Card icon="📖" title={`${framework} control mappings`}>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 12 }}>
          {result.nistControls.map((c, i) => <span key={i} style={{ fontSize: 12, fontFamily: "monospace", padding: "3px 10px", borderRadius: 99, background: "#f1f5f9", border: "1px solid #e2e8f0", color: "#475569" }}>{c.id}</span>)}
        </div>
        <ul style={{ paddingLeft: "1.25rem", display: "flex", flexDirection: "column", gap: 6 }}>
          {result.nistControls.map((c, i) => <li key={i} style={{ fontSize: 13, lineHeight: 1.6 }}><strong>{c.id} – {c.name}:</strong> {c.rationale}</li>)}
        </ul>
      </Card>
    </div>
  );
}

function Card({ icon, title, children }) {
